    private SemanticFormula createFormula(String latex, BoundingBox bbox) {
        SemanticFormula formula = new SemanticFormula(bbox, latex);
        formula.setRecognizedStructureId(StaticLayoutContainers.incrementContentId());
        return formula;
    }

