cat > /tmp/odl_repro_spacing.sh <<'SH'
#!/usr/bin/env bash
ROOT=/workspace/opendataloader-pdf
WORK=${TMPDIR:-/tmp}/odl-spacing-repro
PDF=$WORK/spacing.pdf
OUT=$WORK/out
rm -rf "$WORK"
mkdir -p "$OUT"
perl - <<'PERL' "$PDF"
use strict;
use warnings;
my ($path) = @ARGV;
my $stream = <<'STREAM';
BT
/F1 18 Tf
-3 Tw
1 0 0 1 72 720 Tm (Evolution Of Search) Tj
/F1 14 Tf
-2.5 Tw
1 0 0 1 72 680 Tm (Lexical Search:) Tj
/F1 12 Tf
-2 Tw
1 0 0 1 72 650 Tm (Traditional search relies on keyword matching, retrieving exact keywords or phrases entered by the user) Tj
ET
STREAM
my @objs;
push @objs, "1 0 obj\n<< /Type /Catalog /Pages 2 0 R >>\nendobj\n";
push @objs, "2 0 obj\n<< /Type /Pages /Kids [3 0 R] /Count 1 >>\nendobj\n";
push @objs, "3 0 obj\n<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] /Resources << /Font << /F1 4 0 R >> >> /Contents 5 0 R >>\nendobj\n";
push @objs, "4 0 obj\n<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>\nendobj\n";
push @objs, "5 0 obj\n<< /Length " . length($stream) . " >>\nstream\n$stream\nendstream\nendobj\n";
open my $fh, '>:raw', $path or die $!;
print $fh "%PDF-1.4\n";
my @offsets = (0);
for my $obj (@objs) { push @offsets, tell($fh); print $fh $obj; }
my $xref = tell($fh);
print $fh "xref\n0 " . (scalar(@objs) + 1) . "\n0000000000 65535 f \n";
for my $i (1..$#offsets) { printf $fh "%010d 00000 n \n", $offsets[$i]; }
print $fh "trailer\n<< /Size " . (scalar(@objs) + 1) . " /Root 1 0 R >>\nstartxref\n$xref\n%%EOF\n";
close $fh;
PERL
java -jar "$ROOT/java/opendataloader-pdf-cli/target/opendataloader-pdf-cli-0.0.0.jar" --format markdown-with-html --image-output off --quiet --output-dir "$OUT" "$PDF"
echo "--- markdown ---"
cat "$OUT/spacing.md"
SH
chmod +x /tmp/odl_repro_spacing.sh
/tmp/odl_repro_spacing.sh; echo EXIT:$?

